/**
* `ListBoxMenu` is a simple container node that isolates the `list-box__menu`
* class into a single component. It is also being used to validate given
* `children` components.
*/
const ListBoxMenu = forwardRef(({ children, id, ...rest }, ref) => {
	return /* @__PURE__ */ jsx("ul", {
		ref,
		id,
		className: `${usePrefix()}--list-box__menu`,
		role: "listbox",
		...rest,
		children
	});
});
ListBoxMenu.displayName = "ListBoxMenu";
ListBoxMenu.propTypes = {
	children: PropTypes.oneOfType([
		PropTypes.node,
		PropTypes.arrayOf(PropTypes.oneOf([ListBoxMenuItem])),
		PropTypes.shape({ type: PropTypes.oneOf([ListBoxMenuItem]) }),
		PropTypes.bool
	]),
	id: PropTypes.string.isRequired
};

//#endregion
export { ListBoxMenu as default };